import{_ as t,o as r,c as s,ag as n}from"./chunks/framework.6ZJjlmu_.js";const p=JSON.parse('{"title":"Event bus and records","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/event-bus-and-records.md","filePath":"concepts/event-bus-and-records.md"}'),a={name:"concepts/event-bus-and-records.md"};function o(d,e,i,c,l,u){return r(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="event-bus-and-records" tabindex="-1">Event bus and records <a class="header-anchor" href="#event-bus-and-records" aria-label="Permalink to &quot;Event bus and records&quot;">​</a></h1><h2 id="eventbus" tabindex="-1">EventBus <a class="header-anchor" href="#eventbus" aria-label="Permalink to &quot;EventBus&quot;">​</a></h2><p><code>EventBus</code> is the central <strong>append-only</strong> store for everything the window shows. Instrumentation (ILPP and, optionally, reflection-based discovery) calls into it to append <strong>immutable</strong> records.</p><p>Characteristics:</p><ul><li><strong>Ring buffer</strong> — fixed capacity; oldest records are evicted when full (counters are adjusted accordingly).</li><li><strong>Thread safety</strong> — internal locking around the ring and derived structures used by the UI.</li><li><strong>Editor-oriented</strong> — designed for Play Mode debugging, not shipping player builds as a telemetry bus.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Treat <code>EventBus</code> as an implementation detail for <strong>reading</strong> in custom tooling if you must; prefer the <strong>Event Monitor</strong> window for day-to-day use.</p></div><h2 id="eventrecord" tabindex="-1">EventRecord <a class="header-anchor" href="#eventrecord" aria-label="Permalink to &quot;EventRecord&quot;">​</a></h2><p>Each <strong>SUB</strong>, <strong>UNSUB</strong>, or <strong>INVOKE</strong> becomes an <code>EventRecord</code> with:</p><table tabindex="0"><thead><tr><th>Field (conceptual)</th><th>Sub / Unsub</th><th>Invoke</th></tr></thead><tbody><tr><td>Event name</td><td>Yes</td><td>Yes</td></tr><tr><td>Owner type name</td><td>Yes</td><td>Yes</td></tr><tr><td>Owner instance id</td><td>Yes</td><td>Yes</td></tr><tr><td>Action type</td><td>Subscribed / Unsubscribed</td><td>Invoked</td></tr><tr><td>Subscriber type / method</td><td>Yes</td><td>N/A</td></tr><tr><td>Subscriber count</td><td>N/A</td><td>Yes (from live state)</td></tr><tr><td>Parameters</td><td>N/A</td><td>Optional (payload capture)</td></tr></tbody></table><p>Records are <strong>never mutated</strong> after creation; the log is a timeline you can filter, export, and scrub for time travel.</p><h2 id="live-subscriber-state" tabindex="-1">Live subscriber state <a class="header-anchor" href="#live-subscriber-state" aria-label="Permalink to &quot;Live subscriber state&quot;">​</a></h2><p>Alongside the ring, the bus maintains a <strong>live</strong> map keyed by <code>OwnerTypeName::EventName</code> with a set of <code>&quot;SubscriberType::MethodName&quot;</code> entries. This drives:</p><ul><li><strong>Subscriber count</strong> on <strong>INVOKE</strong> rows (without re-reading delegate fields in injected IL).</li><li>The <strong>Subscribers</strong> tab and time-travel replay.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The live map key does <strong>not</strong> include instance id. Multiple instances of the same owner type share one bucket per event name for counting purposes. Instance id still appears on individual records for context.</p></div><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./ilpp-vs-reflection-scanner.html">ILPP vs ReflectionScanner</a></li><li><a href="./time-travel-and-subscribers.html">Time travel and subscribers</a></li><li><a href="./../reference/event-bus-api.html">EventBus API reference</a></li></ul>',16)])])}const h=t(a,[["render",o]]);export{p as __pageData,h as default};
